import { defineAgent } from "eve";

export default defineAgent({
  model: "anthropic/claude-sonnet-4.6",
  description:
    "Audits supplied URLs or sitemaps for practical SEO issues, compares against local history, and writes concise Markdown reports."
});

import { defineSandbox } from "eve/sandbox";

export default defineSandbox({
  async bootstrap({ use }) {
    const sandbox = await use();
    await sandbox.run({
      command: "mkdir -p reports/seo-audit/history reports/seo-audit/assets"
    });
  }
});

import { defineSchedule } from "eve/schedules";

export default defineSchedule({
  cron: "0 9 * * 1",
  timezone: "UTC",
  prompt:
    "Run the weekly SEO audit for https://example.com or its sitemap. Replace this placeholder with the production URL before enabling the schedule. Compare against reports/seo-audit/history and write reports/seo-audit/latest.md."
});
